mapper.sql:
SELECT '0' AS CHK , IVLC.CTKEY /* 센터코드 */ , CT.CTNM /* 센터명 */ , IVLC.OWKEY /* 화주코드 */ , OW.OWNM /* 화주명 */ , LC.ZNKEY /* 존코드 */ , ZN.ZNNM /* 존명 */ , LC.ARKEY /* 구역코드 */ , AR.ARNM /* 구역명 */ , REP_LC.ZNKEY AS REPZNKEY /* 대표 로케이션 존코드 */ , REP_LC.ZNNM AS REPZNNM /* 대표 로케이션 존명 */ , REP_LC.ARKEY AS REPARKEY /* 대표 로케이션 구역코드 */ , REP_LC.ARNM AS REPARNM /* 대표 로케이션 구역명 */ , IC.LCKEY AS REPLCKEY /* 대표 로케이션 */ , REP_LC.LCSTORGTYPECD AS REPLCSTORGTYPECD /* 대표 로케이션 보관유형 */ , REP_LC.SKUCOUNT AS REPSKUCOUNT /* 대표 로케이션 적치 SKU */ , REP_LC.IVCNTRMGMTYN AS REPIVCNTRMGMTYN /* 대표로케이션 재고용기관리여부 */ , IVLC.LCKEY /* 로케이션코드 */ , IVLC.LCKEY AS FRLCKEY /* 로케이션코드 */ , LC.LCSTORGTYPECD /* 로케이션 보관유형 */ , IVLC.IVSERIALNO /* 용기번호 */ , IVLC.IVSERIALNO AS FRIVSERIALNO /* 용기번호 */ , IVLC.ICKEY /* 상품코드 */ , IC.ICNM /* 상품명 */ , BC.BARCODE /* 상품바코드 */ , IVLC.IVATKEY /* 재고속성 */ , IV.EXPDATE /* 유통기한 */ , IVLC.TOTQTY /* 총수량 */ , IVLC.AVQTY /* 가용수량 */ , IVLC.INSERTDATE , IVLC.INSERTURKEY , IVLC.UPDATEDATE , IVLC.UPDATEURKEY , ( SELECT STRING_AGG(ICUNITTYPECD, '_' ORDER BY ICUNITTYPECD) FROM TWORK_MST_ICUTXTYPE WHERE CTKEY = IC.CTKEY AND OWKEY = IC.OWKEY AND ICKEY = IC.ICKEY ) AS ICUNITTYPE_LIST , ( SELECT STRING_AGG(ICUNITTYPECD||'|'||ICUNITQTY, ',' ORDER BY ICUNITTYPECD) FROM TWORK_MST_ICUTXTYPE WHERE CTKEY = IC.CTKEY AND OWKEY = IC.OWKEY AND ICKEY = IC.ICKEY ) AS ICUNITTYPE_QTY_ARR FROM TWORK_INFO_IVATXLC IVLC INNER JOIN TWORK_INFO_IVAT IV ON IV.CTKEY = IVLC.CTKEY AND IV.OWKEY = IVLC.OWKEY AND IV.ICKEY = IVLC.ICKEY AND IV.IVATKEY = IVLC.IVATKEY INNER JOIN TWORK_MST_LC LC ON LC.CTKEY = IVLC.CTKEY AND LC.LCKEY = IVLC.LCKEY INNER JOIN TWORK_MST_AR AR ON AR.CTKEY = LC.CTKEY AND AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY INNER JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = IVLC.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = IVLC.OWKEY INNER JOIN TWORK_MST_IC IC ON IC.CTKEY = IVLC.CTKEY AND IC.OWKEY = IVLC.OWKEY AND IC.ICKEY = IVLC.ICKEY LEFT JOIN ( SELECT LC.CTKEY , ZN.ZNKEY , ZN.ZNNM , AR.ARKEY , AR.ARNM , LC.LCKEY , LC.LCSTORGTYPECD , LC.IVCNTRMGMTYN , COUNT(DISTINCT IVLC.ICKEY) AS SKUCOUNT FROM TWORK_MST_LC LC INNER JOIN TWORK_MST_AR AR ON AR.CTKEY = LC.CTKEY AND AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY INNER JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY LEFT JOIN TWORK_INFO_IVATXLC IVLC ON IVLC.CTKEY = LC.CTKEY AND IVLC.OWKEY = COALESCE(NULL, 'DAISO') AND IVLC.LCKEY = LC.LCKEY AND IVLC.TOTQTY > 0 GROUP BY LC.CTKEY , ZN.ZNKEY , ZN.ZNNM , AR.ARKEY , AR.ARNM , LC.LCKEY , LC.LCSTORGTYPECD , LC.IVCNTRMGMTYN ) REP_LC ON REP_LC.CTKEY = IC.CTKEY AND REP_LC.LCKEY = IC.LCKEY LEFT JOIN TWORK_MST_ICBARCODE BC ON BC.CTKEY = IC.CTKEY AND BC.OWKEY = IC.OWKEY AND BC.ICKEY = IC.ICKEY AND BC.UOM = IC.UOM AND BC.USEYN = 'Y'
AND IVLC.OWKEY = COALESCE(#{owkey}, #{sowkey}) AND IVLC.TOTQTY > 0 AND IVLC.AVQTY > 0
AND #{SEARCH_CONDITION}

