/* wms-inventory-invnmove-sql-oracle.xml - selectMoveZone */ SELECT LC.LCKEY AS FIELD1 , LC.LCTYPECD AS FIELD2 , LC.LCSTORGTYPECD AS FIELD3 , COUNT(DISTINCT IVLC.ICKEY) AS FIELD4 , CASE WHEN COALESCE(LC.IVCNTRMGMTYN, 'N') = 'Y' THEN MAX(CASE IVLC.IVSERIALNO WHEN 'NA' THEN '' ELSE IVLC.IVSERIALNO END) ELSE '' END AS FIELD5 , ZN.ZNNM AS FIELD6 , AR.ARNM AS FIELD7 , LC.CTKEY , LC.ZNKEY , ZN.ZNNM , LC.ARKEY , AR.ARNM , LC.LCKEY , LC.LCTYPECD , LC.LCSTORGTYPECD , LCTYP.CTCDDTNM AS LCSTORGTYPENM /* 로케이션유형명 */ , LC.IVCNTRMGMTYN , COUNT(DISTINCT IVLC.ICKEY) AS SKUCOUNT , CASE WHEN COALESCE(LC.IVCNTRMGMTYN, 'N') = 'Y' THEN MAX(CASE IVLC.IVSERIALNO WHEN 'NA' THEN '' ELSE IVLC.IVSERIALNO END) ELSE '' END AS IVSERIALNO , MAX(IVLC.IVSERIALDIVCD) AS IVSERIALDIVCD , CASE WHEN COALESCE(LC.IVCNTRMGMTYN, 'N') = 'Y' AND MAX(CASE IVLC.IVSERIALNO WHEN 'NA' THEN '' ELSE IVLC.IVSERIALNO END) IS NOT NULL THEN LC.LCKEY||' ['||MAX(CASE IVLC.IVSERIALNO WHEN 'NA' THEN '' ELSE IVLC.IVSERIALNO END)||']' ELSE LC.LCKEY END AS LCKEYNM FROM TWORK_MST_LC LC INNER JOIN TWORK_MST_AR AR ON AR.CTKEY = LC.CTKEY AND AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY INNER JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = LC.CTKEY LEFT JOIN TWORK_INFO_IVATXLC IVLC ON IVLC.CTKEY = LC.CTKEY AND IVLC.OWKEY = COALESCE(NULL, 'DAISO') AND IVLC.LCKEY = LC.LCKEY AND IVLC.TOTQTY > 0 LEFT JOIN TWORK_MST_CTCD_DT LCTYP ON LCTYP.CTKEY = LC.CTKEY AND LCTYP.CTCDHDKEY = 'LCSTORGTYPECD' AND LCTYP.CTCDDTKEY = LC.LCSTORGTYPECD AND LCTYP.LAKEY = 'KOR'
WHERE LC.CTKEY = COALESCE(#{ctkey}, #{sctkey}) AND ZN.ZNTYPECD = '60'
GROUP BY LC.CTKEY , LC.ZNKEY , ZN.ZNNM , LC.ARKEY , AR.ARNM , LC.LCKEY , LC.LCTYPECD , LC.LCSTORGTYPECD , LC.IVCNTRMGMTYN , LCTYP.CTCDDTNM

/* wms-inventory-invnmove-sql-oracle.xml - selectIvatkey */
SELECT IVATKEY
  FROM TWORK_INFO_IVAT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ICKEY = #{ickey}
   AND COALESCE(EXPDATE, 'NA') = COALESCE(#{expdate}, 'NA')

