/* wms-inventory-invnmove-sql-oracle.xml - selectInvnAdMoveExcelInsertList */ WITH T_CODE AS ( SELECT DT.CTKEY , DT.CTCDHDKEY , DT.CTCDDTKEY , DT.CTCDDTNM FROM TWORK_MST_CTCD_HD HD INNER JOIN TWORK_MST_CTCD_DT DT ON DT.CTKEY = HD.CTKEY AND DT.CTCDHDKEY = HD.CTCDHDKEY
AND HD.CTKEY = #{ctkey} AND DT.CTCDHDKEY IN ( 'ICUNITTYPECD', 'IVMOVERSNCD' ) AND DT.LAKEY = #{lakey} AND HD.DELYN = 'N' AND DT.DELYN = 'N'
) SELECT TMP.CTKEY , TMP.OWKEY , TMP.ICKEY , TMP.FRLCKEY AS LCKEY , TMP.FRLCKEY , TMP.TOLCKEY , IVAT.IVATKEY , CD1.CTCDDTKEY AS UOM , TMP.QTY AS UOMQTY , TMP.PLCMCNTRNO , CD2.CTCDDTKEY AS IVMOVERSNCD , TMP.IVMOVEDTCONT FROM TWORK_UPLOAD_IV_AD_MOVE TMP LEFT JOIN TWORK_INFO_IVAT IVAT ON IVAT.CTKEY = TMP.CTKEY AND IVAT.OWKEY = TMP.OWKEY AND IVAT.ICKEY = TMP.ICKEY AND COALESCE(IVAT.EXPDATE, 'NA') = COALESCE(TMP.EXPDATE, 'NA') LEFT JOIN T_CODE CD1 ON CD1.CTKEY = TMP.CTKEY AND CD1.CTCDHDKEY = 'ICUNITTYPECD' AND CD1.CTCDDTNM = TMP.UOM LEFT JOIN T_CODE CD2 ON CD2.CTKEY = TMP.CTKEY AND CD2.CTCDHDKEY = 'IVMOVERSNCD' AND CD2.CTCDDTNM = TMP.IVMOVERSNCD WHERE TMP.ULHSKEY = #{upldkey} AND TMP.CTKEY = #{ctkey} AND TMP.ERROR_CD IS NULL
